results.candidate_sql:
SELECT COUNT(*) 
FROM frpm 
WHERE "County Name" = 'Amador' AND "Low Grade" = '9' AND "High Grade" = '12';

SELECT sname, cname 
FROM (
    SELECT *, ROW_NUMBER() OVER (ORDER BY NumGE1500 DESC) AS rn 
    FROM satscores
) AS t 
WHERE rn = 1;

SELECT NCESDist 
FROM schools 
WHERE SOC = '31' AND NOT StatusType IS NULL;

SELECT 
    ROUND(
        (
            SUM(CASE WHEN status = 'A' THEN amount ELSE 0 END)::float 
            / 
            NULLIF(SUM(amount), 0)
        ) * 100, 
        2
    ) AS percentage_fully_paid
FROM loan;

SELECT DISTINCT a.account_id
FROM account a
WHERE a.frequency = 'POPLATEK MESICNE';

SELECT (SUM(CASE WHEN district.A3 = 'North Bohemia' THEN district.A16 ELSE 0 END) - 
        SUM(CASE WHEN district.A3 = 'East Bohemia' THEN district.A16 ELSE 0 END)) AS crime_difference
FROM district;

SELECT ROUND(
    (COUNT(CASE WHEN c.gender = 'M' AND a.frequency = 'POPLATEK TYDNE' THEN 1 END) * 100.0 / 
     COUNT(CASE WHEN a.frequency = 'POPLATEK TYDNE' THEN 1 END)), 2
)
FROM account a
JOIN client c ON a.district_id = c.district_id;

SELECT AVG(o_count) FROM (
  SELECT molecule_id, COUNT(*) as o_count 
  FROM atom 
  WHERE element = 'O' AND molecule_id IN (
    SELECT molecule_id 
    FROM bond 
    WHERE bond_type = '-'
  )
  GROUP BY molecule_id
) t;

SELECT COUNT(DISTINCT a.atom_id)
FROM atom a
WHERE a.element != 'Br';

SELECT c.bond_id 
FROM connected c, atom a 
WHERE a.atom_id = 'TR000_2' AND c.atom_id2 = a.atom_id;

SELECT ROUND(
  (CAST(COUNT(CASE WHEN label = '+' THEN 1 END) AS FLOAT) / 
   CAST(COUNT(*) AS FLOAT)) * 100, 
  3
)
FROM molecule;

SELECT ROUND(CAST((COUNT(CASE WHEN a.element = 'h' THEN 1 END) * 100.0) AS DECIMAL(5,4)) / COUNT(*), 4) as percentage 
FROM atom a 
WHERE molecule_id = 'TR206';

SELECT COUNT(*) 
FROM atom 
WHERE element IN ('C', 'H');

SELECT DISTINCT m.molecule_id 
FROM molecule m 
WHERE m.label = '-';

SELECT CASE WHEN label = '+' THEN 'Yes' ELSE 'No' END AS is_carcinogenic 
FROM molecule 
WHERE molecule_id = 'TR124';

SELECT element 
FROM atom 
WHERE atom_id = 'TR000_1';

SELECT ROUND(
  (COUNT(CASE WHEN f.language = 'Chinese Simplified' THEN 1 END) / 
   COUNT(DISTINCT c.id)) * 100, 2
)
FROM cards c
JOIN foreign_data f ON c.uuid = f.uuid;

SELECT COUNT(*) 
FROM cards 
WHERE originalType = 'Summon - Angel' AND subtypes != 'Angel';

SELECT COUNT(*) 
FROM cards 
WHERE frameVersion LIKE '%1993%' AND availability = 'paper' AND hasContentWarning = 1;

SELECT SUM(CAST(REPLACE(SUBSTRING(manaCost, 1, LENGTH(manaCost) - 1), '{', '') AS REAL))
FROM cards 
WHERE artist = 'Rob Alexander';

SELECT ROUND(
  (COUNT(CASE WHEN isOnlineOnly = 1 THEN id END) * 100.0 / NULLIF(COUNT(id), 0)),
  2
)
FROM cards 
WHERE frameEffects LIKE '%legendary%';

SELECT c.name 
FROM cards c 
WHERE c.borderColor = 'black' AND c.isFullArt = 1;

SELECT DISTINCT s.baseSetSize, s.code 
FROM sets s 
WHERE s.block IN ('Masques', 'Mirage');

SELECT COUNT(*) 
FROM cards 
WHERE availability LIKE '%paper%' AND hand = '3';

SELECT artist 
FROM cards 
WHERE flavorName = 'Battra, Dark Destroyer';
